/bin/zsh -lc "node --input-type=module <<'EOF'
import { withDb } from \"./src/db.mjs\";
import { ensureSchema } from \"./src/schema.mjs\";
import { createAccounts, getAccounts, updateAccounts } from \"./src/accounts.mjs\";

await withDb(async (client) => {
  await ensureSchema(client);
  const constraint = await client.query("'`
    SELECT pg_get_constraintdef(oid) AS definition
    FROM pg_constraint
    WHERE conrelid = '"'accounts'::regclass
      AND conname = 'accounts_doc_risk_score'
  "'`);
  if (constraint.rowCount !== 1) throw new Error("riskScore constraint was not installed");

  await client.query("BEGIN");
  try {
    const account = await createAccounts(client, {
      accountId: "acct-risk-boundary-check",
      name: "Boundary Check",
      riskScore: 0,
    });
    if (account.riskScore !== 0) throw new Error("create did not preserve riskScore=0");

    const updated = await updateAccounts(client, account.accountId, { riskScore: 100 });
    if (updated.riskScore !== 100) throw new Error("update did not preserve riskScore=100");
    if ((await getAccounts(client, account.accountId)).riskScore !== 100) {
      throw new Error("get did not return riskScore");
    }

    let rejected = false;
    try {
      await updateAccounts(client, account.accountId, { riskScore: 101 });
    } catch (error) {
      rejected = error instanceof RangeError;
    }
    if (!rejected) throw new Error("out-of-range riskScore was not rejected");
  } finally {
    await client.query("ROLLBACK");
  }
});

console.log("live riskScore boundary check passed");
EOF'

